import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import prescriptionService from '../../services/prescriptionService';

function PrescriptionDetailPage() {
  const { id }       = useParams();
  const navigate     = useNavigate();
  const [rx, setRx]               = useState(null);
  const [loading, setLoading]     = useState(true);
  const [pdfLoading, setPdfLoading] = useState(false);

  useEffect(() => {
    prescriptionService.getPrescription(id)
      .then(data => setRx(data.data))
      .catch(() => {
        toast.error('Prescription not found.');
        navigate('/prescriptions');
      })
      .finally(() => setLoading(false));
  }, [id]);

  // ── PDF Download Handler ─────────────────────────────────────────
  const handleDownloadPDF = async () => {
    setPdfLoading(true);
    try {
      const token    = localStorage.getItem('access_token');
      const response = await fetch(
        `http://localhost:8000/api/v1/prescriptions/${id}/download-pdf/`,
        {
          method:  'GET',
          headers: { Authorization: `Bearer ${token}` },
        }
      );

      if (!response.ok) throw new Error('PDF download failed.');

      const blob     = await response.blob();
      const url      = window.URL.createObjectURL(blob);
      const link     = document.createElement('a');
      link.href      = url;
      link.download  = `prescription-RX-${String(id).padStart(4,'0')}-${rx?.patient_name?.replace(/\s+/g,'_') || 'patient'}.pdf`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      toast.success('Prescription PDF downloaded!');
    } catch (err) {
      toast.error('PDF download failed. Please try again.');
    } finally {
      setPdfLoading(false);
    }
  };

  // ── Loading ──────────────────────────────────────────────────────
  if (loading) return (
    <div className="flex justify-center py-24">
      <svg className="animate-spin w-8 h-8 text-teal-500" fill="none" viewBox="0 0 24 24">
        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
      </svg>
    </div>
  );

  if (!rx) return null;

  return (
    <div className="max-w-2xl mx-auto space-y-4 px-2 pb-10">

      {/* Back */}
      <button
        onClick={() => navigate('/prescriptions')}
        className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-teal-600 transition-colors mt-2"
      >
        ← Back to Prescriptions
      </button>

      {/* ── PDF PREVIEW CARD ── */}
      <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">

        {/* ── PDF HEADER: + Sign + Healthcare Platform ── */}
        <div className="bg-gradient-to-r from-teal-700 via-teal-800 to-teal-900 px-6 pt-6 pb-5">
          <div className="flex items-center justify-between">

            {/* Left: Cross Sign + Brand */}
            <div className="flex items-center gap-3">
              {/* Medical Cross */}
              <div className="relative flex items-center justify-center w-11 h-11 flex-shrink-0">
                <div className="absolute w-4 h-11 bg-white/90 rounded-sm"></div>
                <div className="absolute w-11 h-4 bg-white/90 rounded-sm"></div>
              </div>
              {/* Platform Name */}
              <div>
                <p className="text-white font-extrabold text-lg leading-tight tracking-wide">
                  Healthcare Platform
                </p>
                <p className="text-teal-300 text-[11px] tracking-widest uppercase font-medium mt-0.5">
                  Medical Prescription Record
                </p>
              </div>
            </div>

            {/* Right: RX Badge */}
            <div className="text-right">
              <div className="inline-block bg-white/15 border border-white/25 rounded-xl px-4 py-2">
                <p className="text-teal-200 text-[10px] uppercase tracking-widest font-semibold">
                  Prescription ID
                </p>
                <p className="text-white font-black text-base mt-0.5 tracking-wide">
                  RX-{String(rx.id).padStart(4, '0')}
                </p>
              </div>
            </div>
          </div>

          {/* Divider line */}
          <div className="mt-4 border-t border-teal-600/50"></div>

          {/* Date row */}
          <div className="mt-3 flex items-center gap-2 text-teal-200 text-xs">
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2}
                d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"/>
            </svg>
            <span>
              {new Date(rx.created_at).toLocaleDateString('en-IN', {
                weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
              })}
            </span>
          </div>
        </div>

        {/* ── BODY ── */}
        <div className="px-6 py-5 space-y-4">

          {/* Doctor + Patient */}
          <div className="grid grid-cols-2 gap-3">
            {/* Doctor */}
            <div className="bg-blue-50 border border-blue-100 rounded-xl p-4">
              <p className="text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-2">
                👨‍⚕️ Treating Doctor
              </p>
              <p className="text-sm font-bold text-gray-900 leading-snug">{rx.doctor_name}</p>
              <p className="text-xs text-teal-600 font-semibold mt-0.5">{rx.doctor_specialization}</p>
              <p className="text-xs text-gray-400 mt-1.5 flex items-center gap-1">
                <span>🏥</span> {rx.hospital_name || 'N/A'}
              </p>
            </div>

            {/* Patient */}
            <div className="bg-emerald-50 border border-emerald-100 rounded-xl p-4">
              <p className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest mb-2">
                🧑 Patient
              </p>
              <p className="text-sm font-bold text-gray-900 leading-snug">{rx.patient_name}</p>
              <p className="text-xs text-gray-500 mt-0.5 flex items-center gap-1">
                <span>📞</span> {rx.patient_phone || 'N/A'}
              </p>
              <p className="text-xs text-gray-400 mt-0.5 flex items-center gap-1">
                <span>✉️</span>
                <span className="truncate">{rx.patient_email}</span>
              </p>
            </div>
          </div>

          {/* Diagnosis */}
          <div className="bg-gray-50 border border-gray-100 rounded-xl p-4">
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1.5">
              🔍 Diagnosis
            </p>
            <p className="text-sm font-semibold text-gray-800">{rx.diagnosis}</p>
          </div>

          {/* Medicines */}
          <div className="border border-gray-100 rounded-xl overflow-hidden">
            <div className="bg-teal-600 px-4 py-2.5 flex items-center gap-2">
              <span className="text-base">💊</span>
              <p className="text-white text-xs font-bold uppercase tracking-widest">
                Medicines Prescribed
                <span className="ml-2 bg-white/20 text-white rounded-full px-2 py-0.5 text-[10px]">
                  {rx.medicines?.length || 0}
                </span>
              </p>
            </div>
            <div className="divide-y divide-gray-50 bg-white">
              {rx.medicines?.map((med, i) => (
                <div key={i} className="flex items-start gap-3 px-4 py-3">
                  <div className="w-6 h-6 bg-teal-600 rounded-full flex items-center justify-center
                                  text-white text-[11px] font-black flex-shrink-0 mt-0.5">
                    {i + 1}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-bold text-gray-900">{med.name}</p>
                    <div className="flex flex-wrap gap-2 mt-1">
                      <span className="inline-flex items-center gap-1 text-[11px] text-teal-700
                                       bg-teal-50 border border-teal-100 px-2 py-0.5 rounded-full font-medium">
                        💊 {med.dosage}
                      </span>
                      <span className="inline-flex items-center gap-1 text-[11px] text-gray-600
                                       bg-gray-50 border border-gray-100 px-2 py-0.5 rounded-full font-medium">
                        ⏱ {med.duration}
                      </span>
                    </div>
                    {med.instructions && (
                      <p className="text-[11px] text-gray-500 mt-1.5 italic">
                        📝 {med.instructions}
                      </p>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* General Instructions */}
          {rx.instructions && (
            <div className="bg-amber-50 border border-amber-100 rounded-xl p-4">
              <p className="text-[10px] font-bold text-amber-500 uppercase tracking-widest mb-1.5">
                📋 General Instructions
              </p>
              <p className="text-sm text-gray-700 leading-relaxed">{rx.instructions}</p>
            </div>
          )}

          {/* Follow-up */}
          {rx.follow_up_date && (
            <div className="bg-orange-50 border border-orange-200 rounded-xl p-4 flex items-center gap-3">
              <span className="text-2xl">🔄</span>
              <div>
                <p className="text-[10px] font-bold text-orange-600 uppercase tracking-widest">
                  Follow-up Date
                </p>
                <p className="text-sm font-bold text-orange-800 mt-0.5">
                  {new Date(rx.follow_up_date).toLocaleDateString('en-IN', {
                    weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
                  })}
                </p>
              </div>
            </div>
          )}

          {/* Footer strip */}
          <div className="border-t border-dashed border-gray-200 pt-3 flex items-center justify-between">
            <p className="text-[10px] text-gray-300 tracking-wide uppercase font-medium">
              Healthcare Platform — Confidential Medical Record
            </p>
            <div className="flex items-center gap-1">
              <div className="w-2 h-2 rounded-full bg-teal-400"></div>
              <div className="w-2 h-2 rounded-full bg-teal-600"></div>
              <div className="w-2 h-2 rounded-full bg-teal-800"></div>
            </div>
          </div>
        </div>
      </div>

      {/* ── Download PDF Button ── */}
      <button
        onClick={handleDownloadPDF}
        disabled={pdfLoading}
        className="flex items-center justify-center gap-2 w-full py-3.5
                   text-sm font-bold text-white bg-teal-600 rounded-xl
                   hover:bg-teal-700 active:bg-teal-800 transition-all duration-150
                   disabled:opacity-60 disabled:cursor-not-allowed shadow-md shadow-teal-200"
      >
        {pdfLoading ? (
          <>
            <svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
            </svg>
            Generating PDF...
          </>
        ) : (
          <>
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2}
                d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586
                   a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/>
            </svg>
            Download Prescription PDF
          </>
        )}
      </button>
      <p className="text-xs text-gray-400 text-center -mt-2">
        PDF includes doctor signature, patient details & all medicines
      </p>

    </div>
  );
}

export default PrescriptionDetailPage;
